#include <bits/stdc++.h>
using namespace std;
long long n,a[300005],ans;
void merge_sort(int l,int r){
    if(r-l<=1)return;
	long long mid=l+((r-l)>>1);
	merge_sort(l,mid);
	merge_sort(mid,r);
	long long i=l,j=mid,sum=l,t[n+1];
	while(sum<r){
		if(i>=mid || (a[j]>a[i] && j<r)){ 
			if(i<mid)ans+=mid-i;
			t[sum++]=a[j++];
		}else{
			t[sum++]=a[i++];
		}
	}
	for(int i=l;i<r;i++)
		a[i]=t[i];
}
int main(){
    cin>>n;
    for(int i=1;i<=n;i++)cin>>a[i];
    merge_sort(1,n+1);//排序一个左闭右开的区间 
    //for(int i=1;i<=n;i++)cout<<a[i]<<' ';
    cout<<ans;
    return 0;
}
